public class FizzBuzz {
    public static int fizzBuzz(int n) {
        int count = 0;
        for (int i = 0; i < n; i++) {
            if ((i % 11 == 0 || i % 13 == 0) && String.valueOf(i).contains("7")) {
                count += String.valueOf(i).length() - String.valueOf(i).replace("7", "").length();
            }
        }
        return count;
    }

    public static void main(String[] args) {
        System.out.println(fizzBuzz(50)); // 0
        System.out.println(fizzBuzz(78)); // 2
        System.out.println(fizzBuzz(79)); // 3
    }
}
